from __future__ import annotations

import base64
import hashlib
import subprocess
import sys
import tempfile
import zlib
from pathlib import Path

PATCH_SHA256 = "97dc567ed991fb3f06e8b7830e010abd5cd62f2bda09a9be9d2b39e3baa6fe04"
PATCH_ZLIB_BASE64 = ""

def main() -> None:
    if len(sys.argv) != 2:
        raise SystemExit("Kullanım: apply_calendar_overdue_tracking.py <kaynak-kökü>")
    root = Path(sys.argv[1]).resolve()
    patch = zlib.decompress(base64.b64decode(PATCH_ZLIB_BASE64))
    actual = hashlib.sha256(patch).hexdigest()
    if actual != PATCH_SHA256:
        raise SystemExit(f"Patch SHA uyuşmuyor: {actual}")
    subprocess.run(["git", "init", "-q"], cwd=root, check=True)
    with tempfile.NamedTemporaryFile(suffix=".patch", delete=False) as handle:
        handle.write(patch)
        patch_path = Path(handle.name)
    try:
        subprocess.run(["git", "apply", "--whitespace=nowarn", str(patch_path)], cwd=root, check=True)
    finally:
        patch_path.unlink(missing_ok=True)
    required = [
        "manualOverdueRecordedAt", "manualOverdueDueDates",
        "overdue_calendar_tracking_test", "mizanAccuracyWarning",
        "today.add(const Duration(days: 30))",
    ]
    combined = "\n".join(p.read_text(encoding="utf-8") for p in [
        root / "lib/models/mizan_models.dart",
        root / "lib/services/csv_backup_service.dart",
        root / "lib/services/reminder_engine.dart",
        root / "lib/screens/record_form_dialogs.dart",
        root / "test/overdue_calendar_tracking_test.dart",
    ])
    missing = [item for item in required if item not in combined]
    if missing:
        raise SystemExit(f"Eksik gecikme kapsamı: {missing}")
    print(f"Takvim tabanlı gecikme patch uygulandı: {actual}")

if __name__ == "__main__":
    main()
